mapper.select:
select ti.id track_id, ti.album_id, ti.track_title, ti.cover_url, ti.media_duration, ti.status, max(if(ts.stat_type = '0701',stat_num,-1)) playStatNum, max(if(ts.stat_type = '0702',stat_num,-1)) collectStatNum, max(if(ts.stat_type = '0703',stat_num,-1)) praiseStatNum, max(if(ts.stat_type = '0704',stat_num,-1)) commentStatNum from track_info ti inner join track_stat ts on ti.id = ts.track_id and ts.is_deleted = 0
ti.user_id = #{userId}
and ts.stat_type = #{status}
and ti.track_title like concat('%', #{trackTitle}, '%')
and ti.is_deleted = 0
group by ti.id order by ti.id desc
